qry:select.qry:xquery:
		for $r in sql('

		SELECT
			EMP.c_empresa,
			EMP.d_empresa,
			CAR.c_carpeta,
			CAR.d_carpeta,
			ADE.oi_adelanto,
			ADE.f_adelanto,
			ADE.oi_estado_ant,
			SUJ.c_sujeto,
			SUJ.d_sujeto,
			SUC.c_ubicacion,
			SUC.d_ubicacion,
			EST.c_estado_ant,							
			EST.d_estado_ant,
			ADE.f_anula,
			ADE.f_aprueba

		FROM
			LEG04_ADELANTOS as ADE,
			LEG01_CARPETAS as CAR,
			ORG03_EMPRESAS as EMP,					
     	LEG40_CLASIF_SUJ as CS,
     	LEG40_SUJETOS as SUJ,
     	ORG03_UBICACIONES as SUC,
     	LEG54_ESTADOS_ANT as EST				

		JOIN
			ADE.oi_carpeta INNER CAR.oi_carpeta,
			CAR.oi_empresa INNER EMP.oi_empresa,
			ADE.oi_clasif_sujeto INNER CS.oi_clasif_sujeto,
			CS.oi_sujeto INNER SUJ.oi_sujeto,
			ADE.oi_ubicacion INNER SUC.oi_ubicacion,
			ADE.oi_estado_ant INNER EST.oi_estado_ant																

		WHERE
			1=1
			{%? (#FILTRO:@oi_empresa!='')
				{% AND CAR.oi_empresa = {#FILTRO:@oi_empresa} %}
				{% %}
			%}
			{%? (#FILTRO:@oi_carpeta!='')
				{% AND ADE.oi_carpeta = {#FILTRO:@oi_carpeta} %}
				{% %}
			%}
			{%? (#FILTRO:@oi_adelanto!='')
				{% AND ADE.oi_adelanto = {#FILTRO:@oi_adelanto} %}
				{% %}
			%}
			{%? (#FILTRO:@f_adel_desde!='')
				{% AND ADE.f_adelanto >= {#FILTRO:@f_adel_desde} %}
				{% %}
			%}
			{%? (#FILTRO:@f_adel_hasta!='')
				{% AND ADE.f_adelanto <= ADDDAYS({#FILTRO:@f_adel_hasta},1) %}
				{% %}
			%}
			{%? (#FILTRO:@oi_estado_ant!='')
				{% AND ADE.oi_estado_ant = {#FILTRO:@oi_estado_ant} %}
				{% %}
			%}															
			{%? (#FILTRO:@oi_clasif_sujeto!='')
				{% AND ADE.oi_clasif_sujeto = {#FILTRO:@oi_clasif_sujeto} %}
				{% %}
			%}
			{%? (#FILTRO:@adelantos_anulados!='1')                  
				{% AND ISNULL(ADE.f_anula) %}
				{% %} 
			%}			

		ORDER BY
			c_empresa ASC,
			c_carpeta ASC,
			oi_adelanto ASC


	')/ROWS/ROW
